def prove_axc16i(sys: System) -> Proof:
    """Inference with ~ axc16 as its conclusion.  (Contributed by NM,
    20-May-2008.)  (Proof modification is discouraged.)  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  Use ~ axc16
    instead.  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "axc16i")
    h1 = lb.hyp("axc16i.1", "( x = z → ( φ ↔ ψ ) )")
    h2 = lb.hyp("axc16i.2", "( ψ → ∀ x ψ )")
    s1 = lb.ref("s1", "F/ z x = y", ref="nfv", note="nfv")
    s2 = lb.ref("s2", "F/ x z = y", ref="nfv", note="nfv")
    s3 = lb.ref("s3", "( x = z → ( x = y → z = y ) )", ref="ax7", note="ax7")
    s4 = lb.ref("s4", "( ∀ x x = y → ∀ z z = y )", s1, s2, s3, ref="cbv3", note="cbv3")
    s5 = lb.ref("s5", "( z = x → ( z = y → x = y ) )", ref="ax7", note="ax7")
    s6 = lb.ref("s6", "( ∀ z z = y → x = y )", s5, ref="spimvw", note="spimvw")
    s7 = lb.ref("s7", "( x = y → y = x )", ref="equcomi", note="equcomi")
    s8 = lb.ref("s8", "( z = y → y = z )", ref="equcomi", note="equcomi")
    s9 = lb.ref("s9", "( y = z → ( y = x → z = x ) )", ref="ax7", note="ax7")
    s10 = lb.ref("s10", "( z = y → ( y = x → z = x ) )", s8, s9, ref="syl", note="syl")
    s11 = lb.ref("s11", "( x = y → ( z = y → z = x ) )", s7, s10, ref="syl5com", note="syl5com")
    s12 = lb.ref("s12", "( x = y → ( ∀ z z = y → ∀ z z = x ) )", s11, ref="alimdv", note="alimdv")
    s13 = lb.ref("s13", "( ∀ z z = y → ∀ z z = x )", s6, s12, ref="mpcom", note="mpcom")
    s14 = lb.ref("s14", "( z = x → x = z )", ref="equcomi", note="equcomi")
    s15 = lb.ref("s15", "( ∀ z z = x → ∀ z x = z )", s14, ref="alimi", note="alimi")
    s16 = lb.ref("s16", "( ∀ z z = y → ∀ z x = z )", s13, s15, ref="syl", note="syl")
    s17 = lb.ref("s17", "( φ → ( x = z → ψ ) )", h1, ref="biimpcd", note="biimpcd")
    s18 = lb.ref("s18", "( φ → ( ∀ z x = z → ∀ z ψ ) )", s17, ref="alimdv", note="alimdv")
    s19 = lb.ref("s19", "F/ x ψ", h2, ref="nf5i", note="nf5i")
    s20 = lb.ref("s20", "F/ z φ", ref="nfv", note="nfv")
    s21 = lb.ref("s21", "( z = x → x = z )", ref="equcomi", note="equcomi")
    s22 = lb.ref("s22", "( x = z → ( ψ → φ ) )", h1, ref="biimprd", note="biimprd")
    s23 = lb.ref("s23", "( z = x → ( ψ → φ ) )", s21, s22, ref="syl", note="syl")
    s24 = lb.ref("s24", "( ∀ z ψ → ∀ x φ )", s19, s20, s23, ref="cbv3", note="cbv3")
    s25 = lb.ref("s25", "( ∀ z x = z → ( φ → ∀ x φ ) )", s18, s24, ref="syl6com", note="syl6com")
    res = lb.ref("res", "( ∀ x x = y → ( φ → ∀ x φ ) )", s4, s16, s25, ref="3syl", note="3syl")
    return lb.build(res)

