    s1 = lb.ref("s1", "F/ x ∀ x x = y", ref="nfa1", note="nfa1")
    s2 = lb.ref("s2", "( ∀ x x = y → ( ∀ x φ ↔ ∀ x ψ ) )", s1, h1, ref="albid", note="albid")
    s3 = lb.ref("s3", "( ∀ x x = y → ( ∀ x ψ → ∀ y ψ ) )", ref="axc11", note="axc11")
    s4 = lb.ref("s4", "( ∀ x x = y → ( ∀ y ψ → ∀ x ψ ) )", ref="axc11r", note="axc11r")
    s5 = lb.ref("s5", "( ∀ x x = y → ( ∀ x ψ ↔ ∀ y ψ ) )", s3, s4, ref="impbid", note="impbid")
    res = lb.ref("res", "( ∀ x x = y → ( ∀ x φ ↔ ∀ y ψ ) )", s2, s5, ref="bitrd", note="bitrd")
    return lb.build(res)

