def prove_nfald2(sys: System) -> Proof:
    """Variation on ~ nfald which adds the hypothesis that ` x ` and ` y ` are
    distinct in the inner subproof.  (Contributed by Mario Carneiro,
    8-Oct-2016.)  Usage of this theorem is discouraged because it depends on
    ~ ax-13 .  Use ~ nfald instead.  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nfald2")
    h1 = lb.hyp("nfald2.1", "F/ y φ")
    h2 = lb.hyp("nfald2.2", "( ( φ ∧ ¬ ∀ x x = y ) → F/ x ψ )")
    s1 = lb.ref("s1", "F/ y ¬ ∀ x x = y", ref="nfnae", note="nfnae")
    s2 = lb.ref("s2", "F/ y ( φ ∧ ¬ ∀ x x = y )", h1, s1, ref="nfan", note="nfan")
    s3 = lb.ref("s3", "( ( φ ∧ ¬ ∀ x x = y ) → F/ x ∀ y ψ )", s2, h2, ref="nfald", note="nfald")
    s4 = lb.ref("s4", "( φ → ( ¬ ∀ x x = y → F/ x ∀ y ψ ) )", s3, ref="ex", note="ex")
    s5 = lb.ref("s5", "F/ y ∀ y ψ", ref="nfa1", note="nfa1")
    s6 = lb.ref("s6", "( ∀ x x = y → ( ∀ y ψ ↔ ∀ y ψ ) )", ref="biidd", note="biidd")
    s7 = lb.ref("s7", "( ∀ x x = y → ( F/ x ∀ y ψ ↔ F/ y ∀ y ψ ) )", s6, ref="drnf1", note="drnf1")
    s8 = lb.ref("s8", "( ∀ x x = y → F/ x ∀ y ψ )", s5, s7, ref="mpbiri", note="mpbiri")
    res = lb.ref("res", "( φ → F/ x ∀ y ψ )", s4, s8, ref="pm2.61d2", note="pm2.61d2")
    return lb.build(res)

def prove_nfexd2(sys: System) -> Proof:
    """Variation on ~ nfexd which adds the hypothesis that ` x ` and ` y ` are
    distinct in the inner subproof.  (Contributed by Mario Carneiro,
    8-Oct-2016.)  Usage of this theorem is discouraged because it depends on
    ~ ax-13 .  Use ~ nfexd instead.  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nfexd2")
    h1 = lb.hyp("nfald2.1", "F/ y φ")
    h2 = lb.hyp("nfald2.2", "( ( φ ∧ ¬ ∀ x x = y ) → F/ x ψ )")
    s1 = lb.ref("s1", "( ∃ y ψ ↔ ¬ ∀ y ¬ ψ )", ref="df-ex", note="df-ex")
    s2 = lb.ref("s2", "( ( φ ∧ ¬ ∀ x x = y ) → F/ x ¬ ψ )", h2, ref="nfnd", note="nfnd")
    s3 = lb.ref("s3", "( φ → F/ x ∀ y ¬ ψ )", h1, s2, ref="nfald2", note="nfald2")
    s4 = lb.ref("s4", "( φ → F/ x ¬ ∀ y ¬ ψ )", s3, ref="nfnd", note="nfnd")
    res = lb.ref("res", "( φ → F/ x ∃ y ψ )", s1, s4, ref="nfxfrd", note="nfxfrd")
    return lb.build(res)

def prove_exdistrf(sys: System) -> Proof:
    """Distribution of existential quantifiers, with a bound-variable
    hypothesis saying that ` y ` is not free in ` ph ` , but ` x ` can be
    free in ` ph ` (and there is no distinct variable condition on ` x ` and
    ` y ` ).  (Contributed by Mario Carneiro, 20-Mar-2013.)  (Proof
    shortened by Wolf Lammen, 14-May-2018.)  Usage of this theorem is
    discouraged because it depends on ~ ax-13 .  Use ~ exdistr instead.
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "exdistrf")
    h1 = lb.hyp("exdistrf.1", "( ¬ ∀ x x = y → F/ y φ )")
    s1 = lb.ref("s1", "F/ x ∃ x ( φ ∧ ∃ y ψ )", ref="nfe1", note="nfe1")
    s2 = lb.ref("s2", "( ψ → ∃ y ψ )", ref="19.8a", note="19.8a")
    s3 = lb.ref("s3", "( ( φ ∧ ψ ) → ( φ ∧ ∃ y ψ ) )", s2, ref="anim2i", note="anim2i")
    s4 = lb.ref("s4", "( ∃ y ( φ ∧ ψ ) → ∃ y ( φ ∧ ∃ y ψ ) )", s3, ref="eximi", note="eximi")
    s5 = lb.ref("s5", "( ∀ x x = y → ( ( φ ∧ ∃ y ψ ) ↔ ( φ ∧ ∃ y ψ ) ) )", ref="biidd", note="biidd")
    s6 = lb.ref("s6", "( ∀ x x = y → ( ∃ x ( φ ∧ ∃ y ψ ) ↔ ∃ y ( φ ∧ ∃ y ψ ) ) )", s5, ref="drex1", note="drex1")
    s7 = lb.ref("s7", "( ∀ x x = y → ( ∃ y ( φ ∧ ψ ) → ∃ x ( φ ∧ ∃ y ψ ) ) )", s4, s6, ref="imbitrrid", note="imbitrrid")
    s8 = lb.ref("s8", "( ∃ y ( φ ∧ ψ ) → ( ∃ y φ ∧ ∃ y ψ ) )", ref="19.40", note="19.40")
    s9 = lb.ref("s9", "( ¬ ∀ x x = y → ( ∃ y φ → φ ) )", h1, ref="19.9d", note="19.9d")
    s10 = lb.ref("s10", "( ¬ ∀ x x = y → ( ( ∃ y φ ∧ ∃ y ψ ) → ( φ ∧ ∃ y ψ ) ) )", s9, ref="anim1d", note="anim1d")
    s11 = lb.ref("s11", "( ( φ ∧ ∃ y ψ ) → ∃ x ( φ ∧ ∃ y ψ ) )", ref="19.8a", note="19.8a")
    s12 = lb.ref("s12", "( ¬ ∀ x x = y → ( ∃ y ( φ ∧ ψ ) → ∃ x ( φ ∧ ∃ y ψ ) ) )", s8, s10, s11, ref="syl56", note="syl56")
    s13 = lb.ref("s13", "( ∃ y ( φ ∧ ψ ) → ∃ x ( φ ∧ ∃ y ψ ) )", s7, s12, ref="pm2.61i", note="pm2.61i")
    res = lb.ref("res", "( ∃ x ∃ y ( φ ∧ ψ ) → ∃ x ( φ ∧ ∃ y ψ ) )", s1, s13, ref="exlimi", note="exlimi")
    return lb.build(res)

def prove_dvelimf(sys: System) -> Proof:
    """Version of ~ dvelimv without any variable restrictions.  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  (Contributed by
    NM, 1-Oct-2002.)  (Revised by Mario Carneiro, 6-Oct-2016.)  (Proof
    shortened by Wolf Lammen, 11-May-2018.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "dvelimf")
    h1 = lb.hyp("dvelimf.1", "F/ x φ")
    h2 = lb.hyp("dvelimf.2", "F/ z ψ")
    h3 = lb.hyp("dvelimf.3", "( z = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ∀ z ( z = y → φ ) ↔ ψ )", h2, h3, ref="equsal", note="equsal")
    s2 = lb.ref("s2", "( ψ ↔ ∀ z ( z = y → φ ) )", s1, ref="bicomi", note="bicomi")
    s3 = lb.ref("s3", "F/ z ¬ ∀ x x = y", ref="nfnae", note="nfnae")
    s4 = lb.ref("s4", "( ( ¬ ∀ x x = z ∧ ¬ ∀ x x = y ) → F/ x z = y )", ref="nfeqf", note="nfeqf")
    s5 = lb.ref("s5", "( ( ¬ ∀ x x = y ∧ ¬ ∀ x x = z ) → F/ x z = y )", s4, ref="ancoms", note="ancoms")
    s6 = lb.ref("s6", "( ( ¬ ∀ x x = y ∧ ¬ ∀ x x = z ) → F/ x φ )", h1, ref="a1i", note="a1i")
    s7 = lb.ref("s7", "( ( ¬ ∀ x x = y ∧ ¬ ∀ x x = z ) → F/ x ( z = y → φ ) )", s5, s6, ref="nfimd", note="nfimd")
    s8 = lb.ref("s8", "( ¬ ∀ x x = y → F/ x ∀ z ( z = y → φ ) )", s3, s7, ref="nfald2", note="nfald2")
    res = lb.ref("res", "( ¬ ∀ x x = y → F/ x ψ )", s2, s8, ref="nfxfrd", note="nfxfrd")
    return lb.build(res)

def prove_dvelimdf(sys: System) -> Proof:
    """Deduction form of ~ dvelimf .  Usage of this theorem is discouraged
    because it depends on ~ ax-13 .  (Contributed by NM, 7-Apr-2004.)
    (Revised by Mario Carneiro, 6-Oct-2016.)  (Proof shortened by Wolf
    Lammen, 11-May-2018.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "dvelimdf")
    h1 = lb.hyp("dvelimdf.1", "F/ x φ")
    h2 = lb.hyp("dvelimdf.2", "F/ z φ")
    h3 = lb.hyp("dvelimdf.3", "( φ → F/ x ψ )")
    h4 = lb.hyp("dvelimdf.4", "( φ → F/ z χ )")
    h5 = lb.hyp("dvelimdf.5", "( φ → ( z = y → ( ψ ↔ χ ) ) )")
    s1 = lb.ref("s1", "F/ x ( φ → ψ )", h1, h3, ref="nfim1", note="nfim1")
    s2 = lb.ref("s2", "F/ z ( φ → χ )", h2, h4, ref="nfim1", note="nfim1")
    s3 = lb.ref("s3", "( z = y → ( φ → ( ψ ↔ χ ) ) )", h5, ref="com12", note="com12")
    s4 = lb.ref("s4", "( z = y → ( ( φ → ψ ) ↔ ( φ → χ ) ) )", s3, ref="pm5.74d", note="pm5.74d")
    s5 = lb.ref("s5", "( ¬ ∀ x x = y → F/ x ( φ → χ ) )", s1, s2, s4, ref="dvelimf", note="dvelimf")
    s6 = lb.ref("s6", "( φ → ( ( φ → χ ) ↔ χ ) )", ref="pm5.5", note="pm5.5")
    s7 = lb.ref("s7", "( φ → ( F/ x ( φ → χ ) ↔ F/ x χ ) )", h1, s6, ref="nfbidf", note="nfbidf")
    res = lb.ref("res", "( φ → ( ¬ ∀ x x = y → F/ x χ ) )", s5, s7, ref="imbitrid", note="imbitrid")
    return lb.build(res)

def prove_dvelimh(sys: System) -> Proof:
    """Version of ~ dvelim without any variable restrictions.  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  Check out
    ~ dvelimhw for a version requiring fewer axioms.  (Contributed by NM,
    1-Oct-2002.)  (Proof shortened by Wolf Lammen, 11-May-2018.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "dvelimh")
    h1 = lb.hyp("dvelimh.1", "( φ → ∀ x φ )")
    h2 = lb.hyp("dvelimh.2", "( ψ → ∀ z ψ )")
    h3 = lb.hyp("dvelimh.3", "( z = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "F/ x φ", h1, ref="nf5i", note="nf5i")
    s2 = lb.ref("s2", "F/ z ψ", h2, ref="nf5i", note="nf5i")
    s3 = lb.ref("s3", "( ¬ ∀ x x = y → F/ x ψ )", s1, s2, h3, ref="dvelimf", note="dvelimf")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( ψ → ∀ x ψ ) )", s3, ref="nf5rd", note="nf5rd")
    return lb.build(res)

def prove_dvelim(sys: System) -> Proof:
    """This theorem can be used to eliminate a distinct variable restriction on
    ` x ` and ` z ` and replace it with the "distinctor" ` -. A. x x = y `
    as an antecedent. ` ph ` normally has ` z ` free and can be read
    ` ph ( z ) ` , and ` ps ` substitutes ` y ` for ` z ` and can be read
    ` ph ( y ) ` .  We do not require that ` x ` and ` y ` be distinct: if
    they are not, the distinctor will become false (in multiple-element
    domains of discourse) and "protect" the consequent.

    To obtain a closed-theorem form of this inference, prefix the hypotheses
    with ` A. x A. z ` , conjoin them, and apply ~ dvelimdf .

    Other variants of this theorem are ~ dvelimh (with no distinct variable
    restrictions) and ~ dvelimhw (that avoids ~ ax-13 ).  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  Check out
    ~ dvelimhw for a version requiring fewer axioms.  (Contributed by NM,
    23-Nov-1994.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "dvelim")
    h1 = lb.hyp("dvelim.1", "( φ → ∀ x φ )")
    h2 = lb.hyp("dvelim.2", "( z = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( ψ → ∀ z ψ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( ψ → ∀ x ψ ) )", h1, s1, h2, ref="dvelimh", note="dvelimh")
    return lb.build(res)

def prove_dvelimv(sys: System) -> Proof:
    """Similar to ~ dvelim with first hypothesis replaced by a distinct
    variable condition.  Usage of this theorem is discouraged because it
    depends on ~ ax-13 .  Check out ~ dvelimhw for a version requiring fewer
    axioms.  (Contributed by NM, 25-Jul-2015.)  (Proof shortened by Wolf
    Lammen, 30-Apr-2018.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "dvelimv")
    h1 = lb.hyp("dvelimv.1", "( z = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "( φ → ∀ x φ )", ref="ax-5", note="ax-5")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( ψ → ∀ x ψ ) )", s1, h1, ref="dvelim", note="dvelim")
    return lb.build(res)

def prove_dvelimnf(sys: System) -> Proof:
    """Version of ~ dvelim using "not free" notation.  Usage of this theorem is
    discouraged because it depends on ~ ax-13 .  (Contributed by Mario
    Carneiro, 9-Oct-2016.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "dvelimnf")
    h1 = lb.hyp("dvelimnf.1", "F/ x φ")
    h2 = lb.hyp("dvelimnf.2", "( z = y → ( φ ↔ ψ ) )")
    s1 = lb.ref("s1", "F/ z ψ", ref="nfv", note="nfv")
    res = lb.ref("res", "( ¬ ∀ x x = y → F/ x ψ )", h1, s1, h2, ref="dvelimf", note="dvelimf")
    return lb.build(res)

def prove_dveeq2ALT(sys: System) -> Proof:
    """Alternate proof of ~ dveeq2 , shorter but requiring ~ ax-11 .
    (Contributed by NM, 2-Jan-2002.)  (Revised by NM, 20-Jul-2015.)
    (New usage is discouraged.)  (Proof modification is discouraged.)
    """
    lb = ProofBuilder(sys, "dveeq2ALT")
    s1 = lb.ref("s1", "( w = y → ( z = w ↔ z = y ) )", ref="equequ2", note="equequ2")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( z = y → ∀ x z = y ) )", s1, ref="dvelimv", note="dvelimv")
    return lb.build(res)

def prove_equvini(sys: System) -> Proof:
    """A variable introduction law for equality.  Lemma 15 of [Monk2] p. 109,
    however we do not require ` z ` to be distinct from ` x ` and ` y ` .
    Usage of this theorem is discouraged because it depends on ~ ax-13 .  See
    ~ equvinv for a shorter proof requiring fewer axioms when ` z ` is
    required to be distinct from ` x ` and ` y ` .  (Contributed by NM,
    10-Jan-1993.)  (Proof shortened by Andrew Salmon, 25-May-2011.)  (Proof
    shortened by Wolf Lammen, 16-Sep-2023.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "equvini")
    s1 = lb.ref("s1", "( z = x → ( x = y → z = y ) )", ref="equtr", note="equtr")
    s2 = lb.ref("s2", "( z = x → x = z )", ref="equcomi", note="equcomi")
    s3 = lb.ref("s3", "( z = x → ( x = y → ( x = z ∧ z = y ) ) )", s1, s2, ref="jctild", note="jctild")
    s4 = lb.ref("s4", "( ( x = z ∧ z = y ) → ∃ z ( x = z ∧ z = y ) )", ref="19.8a", note="19.8a")
    s5 = lb.ref("s5", "( z = x → ( x = y → ∃ z ( x = z ∧ z = y ) ) )", s3, s4, ref="syl6", note="syl6")
    s6 = lb.ref("s6", "( ¬ z = x → ( x = y → ∀ z x = y ) )", ref="ax13", note="ax13")
    s7 = lb.ref("s7", "∃ z z = x", ref="ax6e", note="ax6e")
    s8 = lb.ref("s8", "( z = x → ( x = y → z = y ) )", ref="equtr", note="equtr")
    s9 = lb.ref("s9", "( z = x → x = z )", ref="equcomi", note="equcomi")
    s10 = lb.ref("s10", "( z = x → ( x = y → ( x = z ∧ z = y ) ) )", s8, s9, ref="jctild", note="jctild")
    s11 = lb.ref("s11", "∃ z ( x = y → ( x = z ∧ z = y ) )", s7, s10, ref="eximii", note="eximii")
    s12 = lb.ref("s12", "( ∀ z x = y → ∃ z ( x = z ∧ z = y ) )", s11, ref="19.35i", note="19.35i")
    s13 = lb.ref("s13", "( ¬ z = x → ( x = y → ∃ z ( x = z ∧ z = y ) ) )", s6, s12, ref="syl6", note="syl6")
    res = lb.ref("res", "( x = y → ∃ z ( x = z ∧ z = y ) )", s5, s13, ref="pm2.61i", note="pm2.61i")
    return lb.build(res)

def prove_equvel(sys: System) -> Proof:
    """A variable elimination law for equality with no distinct variable
    requirements.  Compare ~ equvini .  Usage of this theorem is discouraged
    because it depends on ~ ax-13 .  Use ~ equvelv when possible.
    (Contributed by NM, 1-Mar-2013.)  (Proof shortened by Mario Carneiro,
    17-Oct-2016.)  (Proof shortened by Wolf Lammen, 15-Jun-2019.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "equvel")
    s1 = lb.ref("s1", "( ∀ z ( z = x ↔ z = y ) → ( ∀ z z = x ↔ ∀ z z = y ) )", ref="albi", note="albi")
    s2 = lb.ref("s2", "∃ z z = y", ref="ax6e", note="ax6e")
    s3 = lb.ref("s3", "( ( z = x ↔ z = y ) → ( z = y → z = x ) )", ref="biimpr", note="biimpr")
    s4 = lb.ref("s4", "( z = x → ( z = y → x = y ) )", ref="ax7", note="ax7")
    s5 = lb.ref("s5", "( ( z = x ↔ z = y ) → ( z = y → x = y ) )", s3, s4, ref="syli", note="syli")
    s6 = lb.ref("s6", "( z = y → ( ( z = x ↔ z = y ) → x = y ) )", s5, ref="com12", note="com12")
    s7 = lb.ref("s7", "∃ z ( ( z = x ↔ z = y ) → x = y )", s2, s6, ref="eximii", note="eximii")
    s8 = lb.ref("s8", "( ∀ z ( z = x ↔ z = y ) → ∃ z x = y )", s7, ref="19.35i", note="19.35i")
    s9 = lb.ref("s9", "( z = x → ( z = y → x = y ) )", ref="ax7", note="ax7")
    s10 = lb.ref("s10", "( z = x → ( ∀ z z = y → x = y ) )", s9, ref="spsd", note="spsd")
    s11 = lb.ref("s11", "( ∀ z z = x → ( ∀ z z = y → x = y ) )", s10, ref="sps", note="sps")
    s12 = lb.ref("s12", "( ∀ z z = x → ( ∀ z z = y → ( ∃ z x = y → x = y ) ) )", s11, ref="a1dd", note="a1dd")
    s13 = lb.ref("s13", "( ( ¬ ∀ z z = x ∧ ¬ ∀ z z = y ) → F/ z x = y )", ref="nfeqf", note="nfeqf")
    s14 = lb.ref("s14", "( ( ¬ ∀ z z = x ∧ ¬ ∀ z z = y ) → ( ∃ z x = y → x = y ) )", s13, ref="19.9d", note="19.9d")
    s15 = lb.ref("s15", "( ¬ ∀ z z = x → ( ¬ ∀ z z = y → ( ∃ z x = y → x = y ) ) )", s14, ref="ex", note="ex")
    s16 = lb.ref("s16", "( ( ∀ z z = x ↔ ∀ z z = y ) → ( ∃ z x = y → x = y ) )", s12, s15, ref="bija", note="bija")
    res = lb.ref("res", "( ∀ z ( z = x ↔ z = y ) → x = y )", s1, s8, s16, ref="sylc", note="sylc")
    return lb.build(res)

def prove_equs5a(sys: System) -> Proof:
    """A property related to substitution that unlike ~ equs5 does not require a
    distinctor antecedent.  Usage of this theorem is discouraged because it
    depends on ~ ax-13 .  This proof uses ~ ax12 , see ~ equs5aALT for an
    alternative one using ~ ax-12 but not ~ ax13 .  Usage of the weaker
    ~ equs5av is preferred, which uses ~ ax12v2 , but not ~ ax-13 .
    (Contributed by NM, 2-Feb-2007.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "equs5a")
    s1 = lb.ref("s1", "F/ x ∀ x ( x = y → φ )", ref="nfa1", note="nfa1")
    s2 = lb.ref("s2", "( x = y → ( ∀ y φ → ∀ x ( x = y → φ ) ) )", ref="ax12", note="ax12")
    s3 = lb.ref("s3", "( ( x = y ∧ ∀ y φ ) → ∀ x ( x = y → φ ) )", s2, ref="imp", note="imp")
    res = lb.ref("res", "( ∃ x ( x = y ∧ ∀ y φ ) → ∀ x ( x = y → φ ) )", s1, s3, ref="exlimi", note="exlimi")
    return lb.build(res)

def prove_equs5e(sys: System) -> Proof:
    """A property related to substitution that unlike ~ equs5 does not require a
    distinctor antecedent.  This proof uses ~ ax12 , see ~ equs5eALT for an
    alternative one using ~ ax-12 but not ~ ax13 .  Usage of this theorem is
    discouraged because it depends on ~ ax-13 .  (Contributed by NM,
    2-Feb-2007.)  (Proof shortened by Wolf Lammen, 15-Jan-2018.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "equs5e")
    s1 = lb.ref("s1", "F/ x ∀ x ( x = y → ∃ y φ )", ref="nfa1", note="nfa1")
    s2 = lb.ref("s2", "( x = y → ( ∀ y ∃ y φ → ∀ x ( x = y → ∃ y φ ) ) )", ref="ax12", note="ax12")
    s3 = lb.ref("s3", "( ∃ y φ → ∀ y ∃ y φ )", ref="hbe1", note="hbe1")
    s4 = lb.ref("s4", "( φ → ∀ y ∃ y φ )", s3, ref="19.23bi", note="19.23bi")
    s5 = lb.ref("s5", "( ( x = y ∧ φ ) → ∀ x ( x = y → ∃ y φ ) )", s2, s4, ref="impel", note="impel")
    res = lb.ref("res", "( ∃ x ( x = y ∧ φ ) → ∀ x ( x = y → ∃ y φ ) )", s1, s5, ref="exlimi", note="exlimi")
    return lb.build(res)

def prove_equs45f(sys: System) -> Proof:
    """Two ways of expressing substitution when ` y ` is not free in ` ph ` .
    The implication "to the left" is ~ equs4 and does not require the
    nonfreeness hypothesis.  Theorem ~ sbalex replaces the nonfreeness
    hypothesis with a disjoint variable condition and ~ equs5 replaces it
    with a distinctor antecedent.  (Contributed by NM, 25-Apr-2008.)
    (Revised by Mario Carneiro, 4-Oct-2016.)  Usage of this theorem is
    discouraged because it depends on ~ ax-13 .  Use ~ sbalex instead.
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "equs45f")
    h1 = lb.hyp("equs45f.1", "F/ y φ")
    s1 = lb.ref("s1", "( φ → ∀ y φ )", h1, ref="nf5ri", note="nf5ri")
    s2 = lb.ref("s2", "( ( x = y ∧ φ ) → ( x = y ∧ ∀ y φ ) )", s1, ref="anim2i", note="anim2i")
    s3 = lb.ref("s3", "( ∃ x ( x = y ∧ φ ) → ∃ x ( x = y ∧ ∀ y φ ) )", s2, ref="eximi", note="eximi")
    s4 = lb.ref("s4", "( ∃ x ( x = y ∧ ∀ y φ ) → ∀ x ( x = y → φ ) )", ref="equs5a", note="equs5a")
    s5 = lb.ref("s5", "( ∃ x ( x = y ∧ φ ) → ∀ x ( x = y → φ ) )", s3, s4, ref="syl", note="syl")
    s6 = lb.ref("s6", "( ∀ x ( x = y → φ ) → ∃ x ( x = y ∧ φ ) )", ref="equs4", note="equs4")
    res = lb.ref("res", "( ∃ x ( x = y ∧ φ ) ↔ ∀ x ( x = y → φ ) )", s5, s6, ref="impbii", note="impbii")
    return lb.build(res)

def prove_equs5(sys: System) -> Proof:
    """Lemma used in proofs of substitution properties.  If there is a disjoint
    variable condition on ` x , y ` , then ~ sbalex can be used instead; if
    ` y ` is not free in ` ph ` , then ~ equs45f can be used.  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  (Contributed by
    NM, 14-May-1993.)  (Revised by BJ, 1-Oct-2018.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "equs5")
    s1 = lb.ref("s1", "F/ x ¬ ∀ x x = y", ref="nfna1", note="nfna1")
    s2 = lb.ref("s2", "F/ x ∀ x ( x = y → φ )", ref="nfa1", note="nfa1")
    s3 = lb.ref("s3", "( ¬ ∀ x x = y → ( x = y → ( φ → ∀ x ( x = y → φ ) ) ) )", ref="axc15", note="axc15")
    s4 = lb.ref("s4", "( ¬ ∀ x x = y → ( ( x = y ∧ φ ) → ∀ x ( x = y → φ ) ) )", s3, ref="impd", note="impd")
    s5 = lb.ref("s5", "( ¬ ∀ x x = y → ( ∃ x ( x = y ∧ φ ) → ∀ x ( x = y → φ ) ) )", s1, s2, s4, ref="exlimd", note="exlimd")
    s6 = lb.ref("s6", "( ∀ x ( x = y → φ ) → ∃ x ( x = y ∧ φ ) )", ref="equs4", note="equs4")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( ∃ x ( x = y ∧ φ ) ↔ ∀ x ( x = y → φ ) ) )", s5, s6, ref="impbid1", note="impbid1")
    return lb.build(res)

def prove_dveel1(sys: System) -> Proof:
    """Quantifier introduction when one pair of variables is disjoint.  Usage
    of this theorem is discouraged because it depends on ~ ax-13 .
    (Contributed by NM, 2-Jan-2002.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "dveel1")
    s1 = lb.ref("s1", "( w = y → ( w ∈ z ↔ y ∈ z ) )", ref="elequ1", note="elequ1")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( y ∈ z → ∀ x y ∈ z ) )", s1, ref="dvelimv", note="dvelimv")
    return lb.build(res)

def prove_dveel2(sys: System) -> Proof:
    """Quantifier introduction when one pair of variables is disjoint.  Usage
    of this theorem is discouraged because it depends on ~ ax-13 .
    (Contributed by NM, 2-Jan-2002.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "dveel2")
    s1 = lb.ref("s1", "( w = y → ( z ∈ w ↔ z ∈ y ) )", ref="elequ2", note="elequ2")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( z ∈ y → ∀ x z ∈ y ) )", s1, ref="dvelimv", note="dvelimv")
    return lb.build(res)

def prove_axc14(sys: System) -> Proof:
    """Axiom ~ ax-c14 is redundant if we assume ~ ax-5 .  Remark 9.6 in
    [Megill] p. 448 (p. 16 of the preprint), regarding axiom scheme C14'.

    Note that ` w ` is a dummy variable introduced in the proof.  Its
    purpose is to satisfy the distinct variable requirements of ~ dveel2 and
    ~ ax-5 .  By the end of the proof it has vanished, and the final theorem
    has no distinct variable requirements.  Usage of this theorem is
    discouraged because it depends on ~ ax-13 .  (Contributed by NM,
    29-Jun-1995.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "axc14")
    s1 = lb.ref("s1", "( ¬ ∀ z z = y → ∀ z ¬ ∀ z z = y )", ref="hbn1", note="hbn1")
    s2 = lb.ref("s2", "( ¬ ∀ z z = y → ( w ∈ y → ∀ z w ∈ y ) )", ref="dveel2", note="dveel2")
    s3 = lb.ref("s3", "( ( ¬ ∀ z z = y → w ∈ y ) → ∀ z ( ¬ ∀ z z = y → w ∈ y ) )", s1, s2, ref="hbim1", note="hbim1")
    s4 = lb.ref("s4", "( w = x → ( w ∈ y ↔ x ∈ y ) )", ref="elequ1", note="elequ1")
    s5 = lb.ref("s5", "( w = x → ( ( ¬ ∀ z z = y → w ∈ y ) ↔ ( ¬ ∀ z z = y → x ∈ y ) ) )", s4, ref="imbi2d", note="imbi2d")
    s6 = lb.ref("s6", "( ¬ ∀ z z = x → ( ( ¬ ∀ z z = y → x ∈ y ) → ∀ z ( ¬ ∀ z z = y → x ∈ y ) ) )", s3, s5, ref="dvelim", note="dvelim")
    s7 = lb.ref("s7", "F/ z ∀ z z = y", ref="nfa1", note="nfa1")
    s8 = lb.ref("s8", "F/ z ¬ ∀ z z = y", s7, ref="nfn", note="nfn")
    s9 = lb.ref("s9", "( ∀ z ( ¬ ∀ z z = y → x ∈ y ) ↔ ( ¬ ∀ z z = y → ∀ z x ∈ y ) )", s8, ref="19.21", note="19.21")
    s10 = lb.ref("s10", "( ¬ ∀ z z = x → ( ( ¬ ∀ z z = y → x ∈ y ) → ( ¬ ∀ z z = y → ∀ z x ∈ y ) ) )", s6, s9, ref="imbitrdi", note="imbitrdi")
    res = lb.ref("res", "( ¬ ∀ z z = x → ( ¬ ∀ z z = y → ( x ∈ y → ∀ z x ∈ y ) ) )", s10, ref="pm2.86d", note="pm2.86d")
    return lb.build(res)

def prove_sb6x(sys: System) -> Proof:
    """Equivalence involving substitution for a variable not free.  Usage of
    this theorem is discouraged because it depends on ~ ax-13 .  Usage of
    ~ sb6 is preferred, which requires fewer axioms.  (Contributed by NM,
    2-Jun-1993.)  (Revised by Mario Carneiro, 4-Oct-2016.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sb6x")
    h1 = lb.hyp("sb6x.1", "F/ x φ")
    s1 = lb.ref("s1", "( [ y / x ] φ ↔ φ )", h1, ref="sbf", note="sbf")
    s2 = lb.ref("s2", "( x = y → ( φ ↔ φ ) )", ref="biidd", note="biidd")
    s3 = lb.ref("s3", "( ∀ x ( x = y → φ ) ↔ φ )", h1, s2, ref="equsal", note="equsal")
    res = lb.ref("res", "( [ y / x ] φ ↔ ∀ x ( x = y → φ ) )", s1, s3, ref="bitr4i", note="bitr4i")
    return lb.build(res)

def prove_sbequ5(sys: System) -> Proof:
    """Substitution does not change an identical variable specifier.  Usage of
    this theorem is discouraged because it depends on ~ ax-13 .  (Contributed
    by NM, 15-May-1993.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sbequ5")
