    s2 = lb.ref("s2", "( ∃ w ( ( z = x ∧ w = y ) ∧ φ ) ↔ ( ∃ w ( z = x ∧ w = y ) ∧ φ ) )", h2, ref="19.41", note="19.41")
    s3 = lb.ref("s3", "( ∃ z ∃ w ( ( z = x ∧ w = y ) ∧ φ ) ↔ ∃ z ( ∃ w ( z = x ∧ w = y ) ∧ φ ) )", s2, ref="exbii", note="exbii")
    s4 = lb.ref("s4", "∃ z ∃ w ( z = x ∧ w = y )", ref="2ax6e", note="2ax6e")
    s5 = lb.ref("s5", "( φ ↔ ( ∃ z ∃ w ( z = x ∧ w = y ) ∧ φ ) )", s4, ref="biantrur", note="biantrur")
    s6 = lb.ref("s6", "( φ ↔ ∃ z ∃ w ( ( z = x ∧ w = y ) ∧ φ ) )", s1, s3, s5, ref="3bitr4ri", note="3bitr4ri")
    s7 = lb.ref("s7", "( z = x → ( [ z / x ] [ w / y ] φ ↔ [ w / y ] φ ) )", ref="sbequ12r", note="sbequ12r")
    s8 = lb.ref("s8", "( w = y → ( [ w / y ] φ ↔ φ ) )", ref="sbequ12r", note="sbequ12r")
    s9 = lb.ref("s9", "( ( z = x ∧ w = y ) → ( [ z / x ] [ w / y ] φ ↔ φ ) )", s7, s8, ref="sylan9bb", note="sylan9bb")
    s10 = lb.ref("s10", "( ( ( z = x ∧ w = y ) ∧ [ z / x ] [ w / y ] φ ) ↔ ( ( z = x ∧ w = y ) ∧ φ ) )", s9, ref="pm5.32i", note="pm5.32i")
    s11 = lb.ref("s11", "( ∃ z ∃ w ( ( z = x ∧ w = y ) ∧ [ z / x ] [ w / y ] φ ) ↔ ∃ z ∃ w ( ( z = x ∧ w = y ) ∧ φ ) )", s10, ref="2exbii", note="2exbii")
    res = lb.ref("res", "( φ ↔ ∃ z ∃ w ( ( z = x ∧ w = y ) ∧ [ z / x ] [ w / y ] φ ) )", s6, s11, ref="bitr4i", note="bitr4i")
    return lb.build(res)

