    s3 = lb.ref("s3", "F/ x ( ¬ ∀ x x = t ∧ y = t )", s1, s2, ref="nfan1", note="nfan1")
    s4 = lb.ref("s4", "( y = t → ( x = y ↔ x = t ) )", ref="equequ2", note="equequ2")
    s5 = lb.ref("s5", "( y = t → ( ( x = y → φ ) ↔ ( x = t → φ ) ) )", s4, ref="imbi1d", note="imbi1d")
    s6 = lb.ref("s6", "( ( ¬ ∀ x x = t ∧ y = t ) → ( ( x = y → φ ) ↔ ( x = t → φ ) ) )", s5, ref="adantl", note="adantl")
    s7 = lb.ref("s7", "( ( ¬ ∀ x x = t ∧ y = t ) → ( ∀ x ( x = y → φ ) ↔ ∀ x ( x = t → φ ) ) )", s3, s6, ref="albid", note="albid")
    s8 = lb.ref("s8", "( ¬ ∀ x x = t → ( ( y = t → ∀ x ( x = y → φ ) ) ↔ ( y = t → ∀ x ( x = t → φ ) ) ) )", s7, ref="pm5.74da", note="pm5.74da")
    s9 = lb.ref("s9", "( ¬ ∀ x x = t → ( ∀ y ( y = t → ∀ x ( x = y → φ ) ) ↔ ∀ y ( y = t → ∀ x ( x = t → φ ) ) ) )", s8, ref="albidv", note="albidv")
    s10 = lb.ref("s10", "( [ t / x ] φ ↔ ∀ y ( y = t → ∀ x ( x = y → φ ) ) )", ref="dfsb", note="dfsb")
    s11 = lb.ref("s11", "∃ y y = t", ref="ax6ev", note="ax6ev")
    s12 = lb.ref("s12", "( ∀ x ( x = t → φ ) ↔ ( ∃ y y = t → ∀ x ( x = t → φ ) ) )", s11, ref="a1bi", note="a1bi")
    s13 = lb.ref("s13", "( ∀ y ( y = t → ∀ x ( x = t → φ ) ) ↔ ( ∃ y y = t → ∀ x ( x = t → φ ) ) )", ref="19.23v", note="19.23v")
    s14 = lb.ref("s14", "( ∀ x ( x = t → φ ) ↔ ∀ y ( y = t → ∀ x ( x = t → φ ) ) )", s12, s13, ref="bitr4i", note="bitr4i")
    res = lb.ref("res", "( ¬ ∀ x x = t → ( [ t / x ] φ ↔ ∀ x ( x = t → φ ) ) )", s9, s10, s14, ref="3bitr4g", note="3bitr4g")
    return lb.build(res)

