    s2 = lb.ref("s2", "( ∀ x ( x = y → ∃ y φ ) → [ y / x ] ∃ y φ )", ref="sb2", note="sb2")
    s3 = lb.ref("s3", "( ∀ x ( x = y → ∃ y φ ) → ∀ x [ y / x ] ∃ y φ )", s2, ref="axc4i", note="axc4i")
