    s2 = lb.ref("s2", "( x = y → ( φ ↔ [ y / x ] φ ) )", ref="sbequ12", note="sbequ12")
    res = lb.ref("res", "( ∀ x φ ↔ ∀ y [ y / x ] φ )", h1, s1, s2, ref="cbval", note="cbval")
    return lb.build(res)

