def prove_sb9(sys: System) -> Proof:
    """Commutation of quantification and substitution variables.  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  (Contributed by
    NM, 5-Aug-1993.)  Allow a shortening of ~ sb9i .  (Revised by Wolf Lammen,
    15-Jun-2019.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sb9")
    s1 = lb.ref("s1", "( y = x → ( [ x / y ] φ ↔ [ y / x ] φ ) )", ref="sbequ12a", note="sbequ12a")
    s2 = lb.ref("s2", "( x = y → ( [ x / y ] φ ↔ [ y / x ] φ ) )", s1, ref="equcoms", note="equcoms")
    s3 = lb.ref("s3", "( ∀ x x = y → ( [ x / y ] φ ↔ [ y / x ] φ ) )", s2, ref="sps", note="sps")
    s4 = lb.ref("s4", "( ∀ x x = y → ( ∀ x [ x / y ] φ ↔ ∀ y [ y / x ] φ ) )", s3, ref="dral1", note="dral1")
    s5 = lb.ref("s5", "F/ x ¬ ∀ x x = y", ref="nfnae", note="nfnae")
    s6 = lb.ref("s6", "F/ y ¬ ∀ x x = y", ref="nfnae", note="nfnae")
    s7 = lb.ref("s7", "( ¬ ∀ y y = x → F/ y [ x / y ] φ )", ref="nfsb2", note="nfsb2")
    s8 = lb.ref("s8", "( ¬ ∀ x x = y → F/ y [ x / y ] φ )", s7, ref="naecoms", note="naecoms")
    s9 = lb.ref("s9", "( ¬ ∀ x x = y → F/ x [ y / x ] φ )", ref="nfsb2", note="nfsb2")
    s10 = lb.ref("s10", "( y = x → ( [ x / y ] φ ↔ [ y / x ] φ ) )", ref="sbequ12a", note="sbequ12a")
    s11 = lb.ref("s11", "( x = y → ( [ x / y ] φ ↔ [ y / x ] φ ) )", s10, ref="equcoms", note="equcoms")
    s12 = lb.ref("s12", "( ¬ ∀ x x = y → ( x = y → ( [ x / y ] φ ↔ [ y / x ] φ ) ) )", s11, ref="a1i", note="a1i")
    s13 = lb.ref("s13", "( ¬ ∀ x x = y → ( ∀ x [ x / y ] φ ↔ ∀ y [ y / x ] φ ) )", s5, s6, s8, s9, s12, ref="cbv2", note="cbv2")
    res = lb.ref("res", "( ∀ x [ x / y ] φ ↔ ∀ y [ y / x ] φ )", s4, s13, ref="pm2.61i", note="pm2.61i")
    return lb.build(res)

def prove_sb9i(sys: System) -> Proof:
    """Commutation of quantification and substitution variables.  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  (Contributed by
    NM, 5-Aug-1993.)  (Proof shortened by Wolf Lammen, 15-Jun-2019.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sb9i")
    s1 = lb.ref("s1", "( ∀ x [ x / y ] φ ↔ ∀ y [ y / x ] φ )", ref="sb9", note="sb9")
    res = lb.ref("res", "( ∀ x [ x / y ] φ → ∀ y [ y / x ] φ )", s1, ref="biimpi", note="biimpi")
    return lb.build(res)

def prove_sbhb(sys: System) -> Proof:
    """Two ways of expressing " ` x ` is (effectively) not free in ` ph ` ".
    Usage of this theorem is discouraged because it depends on ~ ax-13 .
    (Contributed by NM, 29-May-2009.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sbhb")
    s1 = lb.ref("s1", "F/ y φ", ref="nfv", note="nfv")
    s2 = lb.ref("s2", "( ∀ x φ ↔ ∀ y [ y / x ] φ )", s1, ref="sb8", note="sb8")
    s3 = lb.ref("s3", "( ( φ → ∀ x φ ) ↔ ( φ → ∀ y [ y / x ] φ ) )", s2, ref="imbi2i", note="imbi2i")
    s4 = lb.ref("s4", "( ∀ y ( φ → [ y / x ] φ ) ↔ ( φ → ∀ y [ y / x ] φ ) )", ref="19.21v", note="19.21v")
    res = lb.ref("res", "( ( φ → ∀ x φ ) ↔ ∀ y ( φ → [ y / x ] φ ) )", s3, s4, ref="bitr4i", note="bitr4i")
    return lb.build(res)

def prove_nfsbd(sys: System) -> Proof:
    """Deduction version of ~ nfsb .  (Contributed by NM, 15-Feb-2013.)  Usage
    of this theorem is discouraged because it depends on ~ ax-13 .  Use
    ~ nfsbv instead.  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nfsbd")
    h1 = lb.hyp("nfsbd.1", "F/ x φ")
    h2 = lb.hyp("nfsbd.2", "( φ → F/ z ψ )")
    s1 = lb.ref("s1", "( φ → ∀ x F/ z ψ )", h1, h2, ref="alrimi", note="alrimi")
    s2 = lb.ref("s2", "( ∀ x F/ z ψ → ( ¬ ∀ z z = y → F/ z [ y / x ] ψ ) )", ref="nfsb4t", note="nfsb4t")
    s3 = lb.ref("s3", "( φ → ( ¬ ∀ z z = y → F/ z [ y / x ] ψ ) )", s1, s2, ref="syl", note="syl")
    s4 = lb.ref("s4", "( ∀ z z = y → F/ z [ y / x ] ψ )", ref="axc16nf", note="axc16nf")
    res = lb.ref("res", "( φ → F/ z [ y / x ] ψ )", s3, s4, ref="pm2.61d2", note="pm2.61d2")
    return lb.build(res)

def prove_nfsb(sys: System) -> Proof:
    """If ` z ` is not free in ` ph ` , then it is not free in ` [ y / x ] ph `
    when ` y ` and ` z ` are distinct.  See ~ nfsbv for a version with an
    additional disjoint variable condition on ` x , z ` but not requiring
    ~ ax-13 .  (Contributed by Mario Carneiro, 11-Aug-2016.)  (Proof
    shortened by Wolf Lammen, 25-Feb-2024.)  Usage of this theorem is
    discouraged because it depends on ~ ax-13 .  Use ~ nfsbv instead.
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nfsb")
    h1 = lb.hyp("nfsb.1", "F/ z φ")
    s1 = lb.ref("s1", "F/ x ⊤", ref="nftru", note="nftru")
    s2 = lb.ref("s2", "( ⊤ → F/ z φ )", h1, ref="a1i", note="a1i")
    s3 = lb.ref("s3", "( ⊤ → F/ z [ y / x ] φ )", s1, s2, ref="nfsbd", note="nfsbd")
    res = lb.ref("res", "F/ z [ y / x ] φ", s3, ref="mptru", note="mptru")
    return lb.build(res)

def prove_hbsb(sys: System) -> Proof:
    """If ` z ` is not free in ` ph ` , then it is not free in ` [ y / x ] ph `
    when ` y ` and ` z ` are distinct.  (Contributed by NM, 12-Aug-1993.)
    Usage of this theorem is discouraged because it depends on ~ ax-13 .
    Use ~ hbsbw instead.  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "hbsb")
    h1 = lb.hyp("hbsb.1", "( φ → ∀ z φ )")
    s1 = lb.ref("s1", "F/ z φ", h1, ref="nf5i", note="nf5i")
    s2 = lb.ref("s2", "F/ z [ y / x ] φ", s1, ref="nfsb", note="nfsb")
    res = lb.ref("res", "( [ y / x ] φ → ∀ z [ y / x ] φ )", s2, ref="nf5ri", note="nf5ri")
    return lb.build(res)

def prove_sb7f(sys: System) -> Proof:
    """This version of ~ dfsb7 does not require that ` ph ` and ` z ` be
    disjoint.  This permits it to be used as a definition for substitution
    in a formalization that omits the logically redundant axiom ~ ax-5 ,
    i.e., that does not have the concept of a variable not occurring in a
    formula.  (Definition ~ dfsb1 is also suitable, but its mixing of free
    and bound variables is distasteful to some logicians.)  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  (Contributed by
    NM, 26-Jul-2006.)  (Revised by Mario Carneiro, 6-Oct-2016.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sb7f")
    h1 = lb.hyp("sb7f.1", "F/ z φ")
    s1 = lb.ref("s1", "( [ z / x ] φ ↔ ∃ x ( x = z ∧ φ ) )", h1, ref="sb5f", note="sb5f")
    s2 = lb.ref("s2", "( [ y / z ] [ z / x ] φ ↔ [ y / z ] ∃ x ( x = z ∧ φ ) )", s1, ref="sbbii", note="sbbii")
    s3 = lb.ref("s3", "( [ y / z ] [ z / x ] φ ↔ [ y / x ] φ )", h1, ref="sbco2", note="sbco2")
    s4 = lb.ref("s4", "( [ y / z ] ∃ x ( x = z ∧ φ ) ↔ ∃ z ( z = y ∧ ∃ x ( x = z ∧ φ ) ) )", ref="sb5", note="sb5")
    res = lb.ref("res", "( [ y / x ] φ ↔ ∃ z ( z = y ∧ ∃ x ( x = z ∧ φ ) ) )", s2, s3, s4, ref="3bitr3i", note="3bitr3i")
    return lb.build(res)

def prove_sb7h(sys: System) -> Proof:
    """This version of ~ dfsb7 does not require that ` ph ` and ` z ` be
    disjoint.  This permits it to be used as a definition for substitution
    in a formalization that omits the logically redundant axiom ~ ax-5 ,
    i.e., that does not have the concept of a variable not occurring in a
    formula.  (Definition ~ dfsb1 is also suitable, but its mixing of free
    and bound variables is distasteful to some logicians.)  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  (Contributed by
    NM, 26-Jul-2006.)  (Proof shortened by Andrew Salmon, 25-May-2011.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sb7h")
    h1 = lb.hyp("sb7h.1", "( φ → ∀ z φ )")
    s1 = lb.ref("s1", "F/ z φ", h1, ref="nf5i", note="nf5i")
    res = lb.ref("res", "( [ y / x ] φ ↔ ∃ z ( z = y ∧ ∃ x ( x = z ∧ φ ) ) )", s1, ref="sb7f", note="sb7f")
    return lb.build(res)

def prove_sb10f(sys: System) -> Proof:
    """Hao Wang's identity axiom P6 in Irving Copi, _Symbolic Logic_ (5th ed.,
    1979), p. 328.  In traditional predicate calculus, this is a sole axiom
    for identity from which the usual ones can be derived.  Usage of this
    theorem is discouraged because it depends on ~ ax-13 .  (Contributed by
    NM, 9-May-2005.)  (Revised by Mario Carneiro, 6-Oct-2016.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sb10f")
    h1 = lb.hyp("sb10f.1", "F/ x φ")
    s1 = lb.ref("s1", "F/ x [ y / z ] φ", h1, ref="nfsb", note="nfsb")
    s2 = lb.ref("s2", "( x = y → ( [ x / z ] φ ↔ [ y / z ] φ ) )", ref="sbequ", note="sbequ")
    s3 = lb.ref("s3", "( ∃ x ( x = y ∧ [ x / z ] φ ) ↔ [ y / z ] φ )", s1, s2, ref="equsexv", note="equsexv")
    res = lb.ref("res", "( [ y / z ] φ ↔ ∃ x ( x = y ∧ [ x / z ] φ ) )", s3, ref="bicomi", note="bicomi")
    return lb.build(res)

def prove_sbal1(sys: System) -> Proof:
    """Check out ~ sbal for a version not dependent on ~ ax-13 .  A theorem
    used in elimination of disjoint variable restriction on ` x ` and ` z `
    by replacing it with a distinctor ` -. A. x x = z ` .  (Contributed by
    NM, 15-May-1993.)  (Proof shortened by Wolf Lammen, 3-Oct-2018.)
    (New usage is discouraged.)  (Proof modification is discouraged.)
    """
    lb = ProofBuilder(sys, "sbal1")
    s1 = lb.ref("s1", "( ¬ ∀ y y = z → ( [ z / y ] ∀ x φ ↔ ∀ y ( y = z → ∀ x φ ) ) )", ref="sb4b", note="sb4b")
    s2 = lb.ref("s2", "F/ y ¬ ∀ x x = z", ref="nfnae", note="nfnae")
    s3 = lb.ref("s3", "( ¬ ∀ x x = z → F/ x y = z )", ref="nfeqf2", note="nfeqf2")
    s4 = lb.ref("s4", "( F/ x y = z → ( ∀ x ( y = z → φ ) ↔ ( y = z → ∀ x φ ) ) )", ref="19.21t", note="19.21t")
    s5 = lb.ref("s5", "( F/ x y = z → ( ( y = z → ∀ x φ ) ↔ ∀ x ( y = z → φ ) ) )", s4, ref="bicomd", note="bicomd")
    s6 = lb.ref("s6", "( ¬ ∀ x x = z → ( ( y = z → ∀ x φ ) ↔ ∀ x ( y = z → φ ) ) )", s3, s5, ref="syl", note="syl")
    s7 = lb.ref("s7", "( ¬ ∀ x x = z → ( ∀ y ( y = z → ∀ x φ ) ↔ ∀ y ∀ x ( y = z → φ ) ) )", s2, s6, ref="albid", note="albid")
    s8 = lb.ref("s8", "( ( ¬ ∀ x x = z ∧ ¬ ∀ y y = z ) → ( [ z / y ] ∀ x φ ↔ ∀ y ∀ x ( y = z → φ ) ) )", s1, s7, ref="sylan9bbr", note="sylan9bbr")
    s9 = lb.ref("s9", "F/ x ¬ ∀ y y = z", ref="nfnae", note="nfnae")
    s10 = lb.ref("s10", "( ¬ ∀ y y = z → ( [ z / y ] φ ↔ ∀ y ( y = z → φ ) ) )", ref="sb4b", note="sb4b")
    s11 = lb.ref("s11", "( ¬ ∀ y y = z → ( ∀ x [ z / y ] φ ↔ ∀ x ∀ y ( y = z → φ ) ) )", s9, s10, ref="albid", note="albid")
    s12 = lb.ref("s12", "( ∀ x ∀ y ( y = z → φ ) ↔ ∀ y ∀ x ( y = z → φ ) )", ref="alcom", note="alcom")
    s13 = lb.ref("s13", "( ¬ ∀ y y = z → ( ∀ x [ z / y ] φ ↔ ∀ y ∀ x ( y = z → φ ) ) )", s11, s12, ref="bitrdi", note="bitrdi")
    s14 = lb.ref("s14", "( ( ¬ ∀ x x = z ∧ ¬ ∀ y y = z ) → ( ∀ x [ z / y ] φ ↔ ∀ y ∀ x ( y = z → φ ) ) )", s13, ref="adantl", note="adantl")
    s15 = lb.ref("s15", "( ( ¬ ∀ x x = z ∧ ¬ ∀ y y = z ) → ( [ z / y ] ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s8, s14, ref="bitr4d", note="bitr4d")
    s16 = lb.ref("s16", "( ¬ ∀ x x = z → ( ¬ ∀ y y = z → ( [ z / y ] ∀ x φ ↔ ∀ x [ z / y ] φ ) ) )", s15, ref="ex", note="ex")
    s17 = lb.ref("s17", "( y = z → ( ∀ x φ ↔ [ z / y ] ∀ x φ ) )", ref="sbequ12", note="sbequ12")
    s18 = lb.ref("s18", "( ∀ y y = z → ( ∀ x φ ↔ [ z / y ] ∀ x φ ) )", s17, ref="sps", note="sps")
    s19 = lb.ref("s19", "( y = z → ( φ ↔ [ z / y ] φ ) )", ref="sbequ12", note="sbequ12")
    s20 = lb.ref("s20", "( ∀ y y = z → ( φ ↔ [ z / y ] φ ) )", s19, ref="sps", note="sps")
    s21 = lb.ref("s21", "( ∀ y y = z → ( ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s20, ref="dral2", note="dral2")
    s22 = lb.ref("s22", "( ∀ y y = z → ( [ z / y ] ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s18, s21, ref="bitr3d", note="bitr3d")
    res = lb.ref("res", "( ¬ ∀ x x = z → ( [ z / y ] ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s16, s22, ref="pm2.61d2", note="pm2.61d2")
    return lb.build(res)

def prove_sbal2(sys: System) -> Proof:
    """Move quantifier in and out of substitution.  (Contributed by NM,
    2-Jan-2002.)  Remove a distinct variable constraint.  (Revised by Wolf
    Lammen, 24-Dec-2022.)  (Proof shortened by Wolf Lammen, 23-Sep-2023.)
    Usage of this theorem is discouraged because it depends on ~ ax-13 .
    Use ~ sbal instead.  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "sbal2")
    s1 = lb.ref("s1", "( y = z → ( ∀ x φ ↔ [ z / y ] ∀ x φ ) )", ref="sbequ12", note="sbequ12")
    s2 = lb.ref("s2", "( ∀ y y = z → ( ∀ x φ ↔ [ z / y ] ∀ x φ ) )", s1, ref="sps", note="sps")
    s3 = lb.ref("s3", "( y = z → ( φ ↔ [ z / y ] φ ) )", ref="sbequ12", note="sbequ12")
    s4 = lb.ref("s4", "( ∀ y y = z → ( φ ↔ [ z / y ] φ ) )", s3, ref="sps", note="sps")
    s5 = lb.ref("s5", "( ∀ y y = z → ( ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s4, ref="dral2", note="dral2")
    s6 = lb.ref("s6", "( ∀ y y = z → ( [ z / y ] ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s2, s5, ref="bitr3d", note="bitr3d")
    s7 = lb.ref("s7", "( ( ¬ ∀ x x = y ∧ ∀ y y = z ) → ( [ z / y ] ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s6, ref="adantl", note="adantl")
    s8 = lb.ref("s8", "( ¬ ∀ y y = z → ( [ z / y ] ∀ x φ ↔ ∀ y ( y = z → ∀ x φ ) ) )", ref="sb4b", note="sb4b")
    s9 = lb.ref("s9", "( ( ¬ ∀ x x = y ∧ ¬ ∀ y y = z ) → ( [ z / y ] ∀ x φ ↔ ∀ y ( y = z → ∀ x φ ) ) )", s8, ref="adantl", note="adantl")
    s10 = lb.ref("s10", "F/ x ¬ ∀ y y = z", ref="nfnae", note="nfnae")
    s11 = lb.ref("s11", "( ¬ ∀ y y = z → ( [ z / y ] φ ↔ ∀ y ( y = z → φ ) ) )", ref="sb4b", note="sb4b")
    s12 = lb.ref("s12", "( ¬ ∀ y y = z → ( ∀ x [ z / y ] φ ↔ ∀ x ∀ y ( y = z → φ ) ) )", s10, s11, ref="albid", note="albid")
    s13 = lb.ref("s13", "( ∀ x ∀ y ( y = z → φ ) ↔ ∀ y ∀ x ( y = z → φ ) )", ref="alcom", note="alcom")
    s14 = lb.ref("s14", "( ¬ ∀ y y = z → ( ∀ x [ z / y ] φ ↔ ∀ y ∀ x ( y = z → φ ) ) )", s12, s13, ref="bitrdi", note="bitrdi")
    s15 = lb.ref("s15", "F/ y ¬ ∀ x x = y", ref="nfnae", note="nfnae")
    s16 = lb.ref("s16", "( ¬ ∀ x x = y → F/ x y = z )", ref="nfeqf1", note="nfeqf1")
    s17 = lb.ref("s17", "( F/ x y = z → ( ∀ x ( y = z → φ ) ↔ ( y = z → ∀ x φ ) ) )", ref="19.21t", note="19.21t")
    s18 = lb.ref("s18", "( ¬ ∀ x x = y → ( ∀ x ( y = z → φ ) ↔ ( y = z → ∀ x φ ) ) )", s16, s17, ref="syl", note="syl")
    s19 = lb.ref("s19", "( ¬ ∀ x x = y → ( ∀ y ∀ x ( y = z → φ ) ↔ ∀ y ( y = z → ∀ x φ ) ) )", s15, s18, ref="albid", note="albid")
    s20 = lb.ref("s20", "( ( ¬ ∀ x x = y ∧ ¬ ∀ y y = z ) → ( ∀ x [ z / y ] φ ↔ ∀ y ( y = z → ∀ x φ ) ) )", s14, s19, ref="sylan9bbr", note="sylan9bbr")
    s21 = lb.ref("s21", "( ( ¬ ∀ x x = y ∧ ¬ ∀ y y = z ) → ( [ z / y ] ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s9, s20, ref="bitr4d", note="bitr4d")
    res = lb.ref("res", "( ¬ ∀ x x = y → ( [ z / y ] ∀ x φ ↔ ∀ x [ z / y ] φ ) )", s7, s21, ref="pm2.61dan", note="pm2.61dan")
    return lb.build(res)

def prove_2sb8e(sys: System) -> Proof:
    """An equivalent expression for double existence.  Usage of this theorem is
    discouraged because it depends on ~ ax-13 .  For a version requiring
    more disjoint variables, but fewer axioms, see ~ 2sb8ef .  (Contributed
    by Wolf Lammen, 2-Nov-2019.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "2sb8e")
    s1 = lb.ref("s1", "F/ w φ", ref="nfv", note="nfv")
    s2 = lb.ref("s2", "( ∃ y φ ↔ ∃ w [ w / y ] φ )", s1, ref="sb8e", note="sb8e")
    s3 = lb.ref("s3", "( ∃ x ∃ y φ ↔ ∃ x ∃ w [ w / y ] φ )", s2, ref="exbii", note="exbii")
    s4 = lb.ref("s4", "( ∃ x ∃ w [ w / y ] φ ↔ ∃ w ∃ x [ w / y ] φ )", ref="excom", note="excom")
    s5 = lb.ref("s5", "( ∃ x ∃ y φ ↔ ∃ w ∃ x [ w / y ] φ )", s3, s4, ref="bitri", note="bitri")
    s6 = lb.ref("s6", "F/ z φ", ref="nfv", note="nfv")
    s7 = lb.ref("s7", "F/ z [ w / y ] φ", s6, ref="nfsb", note="nfsb")
    s8 = lb.ref("s8", "( ∃ x [ w / y ] φ ↔ ∃ z [ z / x ] [ w / y ] φ )", s7, ref="sb8e", note="sb8e")
    s9 = lb.ref("s9", "( ∃ w ∃ x [ w / y ] φ ↔ ∃ w ∃ z [ z / x ] [ w / y ] φ )", s8, ref="exbii", note="exbii")
    s10 = lb.ref("s10", "( ∃ w ∃ z [ z / x ] [ w / y ] φ ↔ ∃ z ∃ w [ z / x ] [ w / y ] φ )", ref="excom", note="excom")
    res = lb.ref("res", "( ∃ x ∃ y φ ↔ ∃ z ∃ w [ z / x ] [ w / y ] φ )", s5, s9, s10, ref="3bitri", note="3bitri")
    return lb.build(res)

def prove_dfmoeu(sys: System) -> Proof:
    """An elementary proof of ~ moeu in disguise, connecting an expression
    characterizing uniqueness ( ~ df-mo ) to that of existential uniqueness
    ( ~ eu6 ).  No particular order of definition is required, as one can be
    derived from the other.  This is shown here and in ~ dfeumo .
    (Contributed by Wolf Lammen, 27-May-2019.)
    """
    lb = ProofBuilder(sys, "dfmoeu")
    s1 = lb.ref("s1", "( ∀ x ¬ φ ↔ ¬ ∃ x φ )", ref="alnex", note="alnex")
    s2 = lb.ref("s2", "( ¬ φ → ( φ → x = y ) )", ref="pm2.21", note="pm2.21")
    s3 = lb.ref("s3", "( ∀ x ¬ φ → ∀ x ( φ → x = y ) )", s2, ref="alimi", note="alimi")
    s4 = lb.ref("s4", "( ¬ ∃ x φ → ∀ x ( φ → x = y ) )", s1, s3, ref="sylbir", note="sylbir")
    s5 = lb.ref("s5", "( ¬ ∃ x φ → ∃ y ∀ x ( φ → x = y ) )", s4, ref="19.8ad", note="19.8ad")
    s6 = lb.ref("s6", "( ( φ ↔ x = y ) → ( φ → x = y ) )", ref="biimp", note="biimp")
    s7 = lb.ref("s7", "( ∀ x ( φ ↔ x = y ) → ∀ x ( φ → x = y ) )", s6, ref="alimi", note="alimi")
    s8 = lb.ref("s8", "( ∃ y ∀ x ( φ ↔ x = y ) → ∃ y ∀ x ( φ → x = y ) )", s7, ref="eximi", note="eximi")
    s9 = lb.ref("s9", "( ( ∃ x φ → ∃ y ∀ x ( φ ↔ x = y ) ) → ∃ y ∀ x ( φ → x = y ) )", s5, s8, ref="ja", note="ja")
    s10 = lb.ref("s10", "F/ x ( ∀ x ( φ → x = y ) → ∀ x ( φ ↔ x = y ) )", ref="nfia1", note="nfia1")
    s11 = lb.ref("s11", "( φ → φ )", ref="id", note="id")
    s12 = lb.ref("s12", "( x = y → ( φ → ∀ x ( x = y → φ ) ) )", ref="ax12v", note="ax12v")
    s13 = lb.ref("s13", "( φ → ( x = y → ∀ x ( x = y → φ ) ) )", s12, ref="com12", note="com12")
    s14 = lb.ref("s14", "( φ → ( ( φ → x = y ) → ∀ x ( x = y → φ ) ) )", s11, s13, ref="embantd", note="embantd")
    s15 = lb.ref("s15", "( φ → ( ∀ x ( φ → x = y ) → ∀ x ( x = y → φ ) ) )", s14, ref="spsd", note="spsd")
    s16 = lb.ref("s16", "( φ → ( ∀ x ( φ → x = y ) → ( ∀ x ( φ → x = y ) ∧ ∀ x ( x = y → φ ) ) ) )", s15, ref="ancld", note="ancld")
    s17 = lb.ref("s17", "( ∀ x ( φ ↔ x = y ) ↔ ( ∀ x ( φ → x = y ) ∧ ∀ x ( x = y → φ ) ) )", ref="albiim", note="albiim")
    s18 = lb.ref("s18", "( φ → ( ∀ x ( φ → x = y ) → ∀ x ( φ ↔ x = y ) ) )", s16, s17, ref="imbitrrdi", note="imbitrrdi")
    s19 = lb.ref("s19", "( ∃ x φ → ( ∀ x ( φ → x = y ) → ∀ x ( φ ↔ x = y ) ) )", s10, s18, ref="exlimi", note="exlimi")
    s20 = lb.ref("s20", "( ∃ x φ → ( ∃ y ∀ x ( φ → x = y ) → ∃ y ∀ x ( φ ↔ x = y ) ) )", s19, ref="eximdv", note="eximdv")
    s21 = lb.ref("s21", "( ∃ y ∀ x ( φ → x = y ) → ( ∃ x φ → ∃ y ∀ x ( φ ↔ x = y ) ) )", s20, ref="com12", note="com12")
    res = lb.ref("res", "( ( ∃ x φ → ∃ y ∀ x ( φ ↔ x = y ) ) ↔ ∃ y ∀ x ( φ → x = y ) )", s9, s21, ref="impbii", note="impbii")
    return lb.build(res)

def prove_dfeumo(sys: System) -> Proof:
    """An elementary proof showing the reverse direction of ~ dfmoeu .  Here
    the characterizing expression of existential uniqueness ( ~ eu6 ) is
    derived from that of uniqueness ( ~ df-mo ).  (Contributed by Wolf
    Lammen, 3-Oct-2023.)
    """
    lb = ProofBuilder(sys, "dfeumo")
    s1 = lb.ref("s1", "∃ x x = y", ref="ax6ev", note="ax6ev")
    s2 = lb.ref("s2", "( ( φ ↔ x = y ) → ( x = y → φ ) )", ref="biimpr", note="biimpr")
    s3 = lb.ref("s3", "( ∀ x ( φ ↔ x = y ) → ( ∃ x x = y → ∃ x φ ) )", s2, ref="aleximi", note="aleximi")
    s4 = lb.ref("s4", "( ∀ x ( φ ↔ x = y ) → ∃ x φ )", s1, s3, ref="mpi", note="mpi")
    s5 = lb.ref("s5", "( ∃ y ∀ x ( φ ↔ x = y ) → ∃ x φ )", s4, ref="exlimiv", note="exlimiv")
    s6 = lb.ref("s6", "( ∃ y ∀ x ( φ ↔ x = y ) ↔ ( ∃ x φ ∧ ∃ y ∀ x ( φ ↔ x = y ) ) )", s5, ref="pm4.71ri", note="pm4.71ri")
    s7 = lb.ref("s7", "( ( ∃ x φ ∧ ∃ y ∀ x ( φ ↔ x = y ) ) ↔ ( ∃ x φ ∧ ( ∃ x φ → ∃ y ∀ x ( φ ↔ x = y ) ) ) )", ref="abai", note="abai")
    s8 = lb.ref("s8", "( ( ∃ x φ → ∃ y ∀ x ( φ ↔ x = y ) ) ↔ ∃ y ∀ x ( φ → x = y ) )", ref="dfmoeu", note="dfmoeu")
    s9 = lb.ref("s9", "( ( ∃ x φ ∧ ( ∃ x φ → ∃ y ∀ x ( φ ↔ x = y ) ) ) ↔ ( ∃ x φ ∧ ∃ y ∀ x ( φ → x = y ) ) )", s8, ref="anbi2i", note="anbi2i")
    res = lb.ref("res", "( ( ∃ x φ ∧ ∃ y ∀ x ( φ → x = y ) ) ↔ ∃ y ∀ x ( φ ↔ x = y ) )", s6, s7, s9, ref="3bitrri", note="3bitrri")
    return lb.build(res)


